  const svelteSource: string = "// In your Svelte component:\nimport MenuBar from \"lily-design-system-svelte-headless/components/MenuBar/MenuBar.svelte\";\n\n<MenuBar>\n  <!-- list children -->\n</MenuBar>\n";
